function isNight(){return false}
function clamp(v,min,max){return Math.max(min,Math.min(max,v))}
function round(v){return Math.round(v)}
function logEvent(t){eventLog.unshift(t);if(eventLog.length>9)eventLog.pop()}

function activeKnownTiles(a){return Object.values(a.knownMap).filter(m=>memoryFreshness(m)>0).length}
function bestActionFromScores(scores){
  let best="",bestVal=-Infinity;
  Object.entries(scores||{}).forEach(([act,val])=>{
    if(val!==null && val>bestVal){best=act;bestVal=val}
  });
  return best;
}
function agentSnapshot(a){
  return {
    x:a.x,y:a.y,alive:a.alive,age:a.age,deaths:a.deaths,
    health:round(a.health),hunger:round(a.hunger),thirst:round(a.thirst),sleep:round(a.sleep),social:round(a.social),
    harvest:Number(a.harvest.toFixed(2)),knownTiles:activeKnownTiles(a),visitedTiles:a.visited.size,
    currentAction:a.currentAction,deathCause:a.deathCause||""
  };
}
function logBehavior(a,act,reward,mapReward,stateBefore,snapBefore,qScoresBefore){
  const snapAfter=agentSnapshot(a);
  const socialClues=a.lastSharedClues||0;
  const mapUpdates=Math.max(0,snapAfter.knownTiles-(snapBefore?.knownTiles||0));
  if(snapBefore?.alive && !a.alive)behaviorStats.deaths++;
  behaviorStats.socialClues+=socialClues;
  behaviorStats.mapUpdates+=mapUpdates;
  behaviorLog.push({
    runId:RUN_ID,
    schemaVersion:1,
    day,
    tick:click,
    agent:a.name,
    personality:a.personality,
    action:act,
    displayedAction:a.currentAction,
    reward:Number(reward.toFixed(2)),
    mapReward:Number(mapReward.toFixed(2)),
    socialClues,
    mapUpdates,
    qBestBefore:bestActionFromScores(qScoresBefore),
    qScoresBefore,
    stateBefore,
    before:snapBefore,
    after:snapAfter,
    world:{droughtActive,locustActive,status:worldStatus()}
  });
}
function downloadTextFile(filename,content,mime){
  const blob=new Blob([content],{type:mime});
  const url=URL.createObjectURL(blob);
  const link=document.createElement("a");
  link.href=url;
  link.download=filename;
  document.body.appendChild(link);
  link.click();
  link.remove();
  setTimeout(()=>URL.revokeObjectURL(url),1000);
}
function behaviorPayload(){
  return {
    runId:RUN_ID,
    exportedAt:new Date().toISOString(),
    simulator:"Jungle Island",
    description:"Emergent AI simulator behavior log generated locally in the browser.",
    daysSimulated:day,
    ticks:click,
    actionsLogged:behaviorLog.length,
    stats:{...behaviorStats},
    agents:agents.map(a=>({name:a.name,personality:a.personality,alive:a.alive,age:a.age,deaths:a.deaths,knownTiles:activeKnownTiles(a),visitedTiles:a.visited.size,lastAction:a.currentAction})),
    records:behaviorLog
  };
}
function exportBehaviorJSON(){
  const filename=`jungle-island-behavior-log-${RUN_ID}.json`;
  downloadTextFile(filename,JSON.stringify(behaviorPayload(),null,2),"application/json;charset=utf-8");
  setPortalStatus(`Downloaded ${filename}`);
}
function csvEscape(v){
  const s=String(v??"");
  return /[",\n]/.test(s)?`"${s.replace(/"/g,'""')}"`:s;
}
function exportBehaviorCSV(){
  const headers=["runId","agent","personality","daysSimulated","actionsLogged","deaths","alive","age","knownTiles","visitedTiles","lastAction","totalReward","avgHealth","avgFood","avgWater","avgSleep","gather","move","sleep","socialize","socialClues","mapUpdates"];
  const rows=agents.map(a=>{
    const logs=behaviorLog.filter(r=>r.agent===a.name);
    const actionsCount=Object.fromEntries(actions.map(act=>[act,logs.filter(r=>r.action===act).length]));
    const avg=key=>logs.length?Math.round(logs.reduce((s,r)=>s+(r.after?.[key]||0),0)/logs.length):0;
    const sumReward=logs.reduce((s,r)=>s+(r.reward||0),0).toFixed(2);
    const socialClues=logs.reduce((s,r)=>s+(r.socialClues||0),0);
    const mapUpdates=logs.reduce((s,r)=>s+(r.mapUpdates||0),0);
    return [RUN_ID,a.name,a.personality,day,logs.length,a.deaths,a.alive,a.age,activeKnownTiles(a),a.visited.size,a.currentAction,sumReward,avg("health"),avg("hunger"),avg("thirst"),avg("sleep"),actionsCount.gather,actionsCount.move,actionsCount.sleep,actionsCount.socialize,socialClues,mapUpdates];
  });
  const csv=[headers,...rows].map(row=>row.map(csvEscape).join(",")).join("\n");
  const filename=`jungle-island-run-summary-${RUN_ID}.csv`;
  downloadTextFile(filename,csv,"text/csv;charset=utf-8");
  setPortalStatus(`Downloaded ${filename}`);
}
function clearBehaviorLog(){
  behaviorLog.length=0;
  behaviorStats.deaths=0;
  behaviorStats.socialClues=0;
  behaviorStats.mapUpdates=0;
  setPortalStatus("Current run log cleared. New actions will be recorded from this point.");
  render();
}
function setPortalStatus(text){
  if(portalStatusEl)portalStatusEl.textContent=text;
}
function updateBehaviorPortal(){
  if(!behaviorPortalEl)return;
  runIdTextEl.textContent=RUN_ID;
  runDaysTextEl.textContent=String(day);
  actionsLoggedTextEl.textContent=behaviorLog.length.toLocaleString();
  deathsLoggedTextEl.textContent=String(behaviorStats.deaths);
  socialCluesTextEl.textContent=String(behaviorStats.socialClues);
  mapUpdatesTextEl.textContent=String(behaviorStats.mapUpdates);
}

function makeAgent(name,initial,color,personality,x,y){
  return {
    name,initial,color,personality,x,y,
    health:100,hunger:80,thirst:80,sleep:80,social:80,harvest:1,
    deaths:0,age:0,alive:true,deadDays:0,deathCause:"",
    q:{},qView:{},last:["Spawned"],lastQ:"🍖",currentAction:"Idle",diary:["Day 1: I woke up on the island."],
    diarySeenDay:1,diarySeenToday:new Set(["Day 1: I woke up on the island."]),
    visited:new Set([x+","+y]),
    resourceMemory:{},
    knownMap:{},
    avoidMemory:{},
    oldWellUses:[],
    lastOldWellLogDay:-999
  };
}

